#!/usr/bin/env bash
# pipeline-cull-raw-retouch-grade-.sh — 后期 Pipeline (Cull → RAW → Retouch → Grade → Deliver) SOP walkthrough for 摄影.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
WORKFLOW="后期 Pipeline (Cull → RAW → Retouch → Grade → Deliver)"

usage() {
  cat <<EOF
pipeline-cull-raw-retouch-grade-.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./pipeline-cull-raw-retouch-grade-.sh             # interactive
  ./pipeline-cull-raw-retouch-grade-.sh --dry-run
  ./pipeline-cull-raw-retouch-grade-.sh --json
  ./pipeline-cull-raw-retouch-grade-.sh --explain
  ./pipeline-cull-raw-retouch-grade-.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "后期 Pipeline (Cull → RAW → Retouch → Grade → Deliver)" 工作流。

一句话: 从一堆 RAW 到交付成片的完整流水线——选片、RAW 调整、像素级精修、调色、色彩管理输出。**全行业衰减最快的工作流**。

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**选片 culling**: 在 Lightroom/Photo Mechanic 里第一遍打星/旗标，筛掉废片（脱焦/闭眼/重复），只留 keeper。跳过 → 对几百张全图无差别精修，时间爆炸、交付质量参差。(evidence: [T03-S007, T03-S008])"
  "**RAW 调整**: 在 LR/Capture One 调曝光/白平衡/对比/高光阴影/色调曲线/HSL/局部蒙版。跳过 → 直接进 PS 精修一张没调好基底的图，事倍功半。(evidence: [T02-S014, T02-S015])"
  "**精修 retouch（人像/商业）**: 进 Photoshop 先 cleanup（去明显瑕疵/杂物）→ 频率分离（高频修纹理、低频修色块）→ dodge & burn 塑立体 → 液化微调形体。顺序：cleanup → FS → D&B → 调色之前。跳过 cleanup 直接 FS → 在大瑕疵上磨皮，事倍功半且不自然。(evidence: [T03-S009, T03-S010])"
  "**调色 grading**: 统一影调/色调（曲线/分离色调/LUT），定整组风格。跳过 → 一组照片色调跳跃不统一。"
  "**输出交付**: 做色彩管理（校色屏 + 按用途转 sRGB 网络/Adobe RGB 或打印 profile + 软打样），导出 + 上传客片平台/图库。跳过色彩管理 → 「我屏上好看，客户/印刷出来偏色」。(evidence: [T02-S026, T02-S027])"
)
declare -a FAILURE_MODES=(
  "**不选片就全量精修**: 对几百张无差别修，时间爆炸 → 永远先 culling 打星只留 keeper 再精修。**CLI 自检**: 「你是先选片只留 keeper，还是想把每张都修？」"
  "**跳过 cleanup 直接频率分离**: 在大瑕疵上磨皮不自然 → 顺序永远 cleanup → FS → D&B。**CLI 自检**: 「频率分离前，明显杂物/大痘清干净了吗？」"
  "**不做色彩管理就交付**: 「我屏好看客户偏色」 → 校色屏 + 按用途转 sRGB/打印 profile + 软打样。**CLI 自检**: 「你的屏校过色吗？导出 profile 匹配交付端（网络 sRGB / 打印 ICC）吗？」"
  "**AI 选片全盘信任**: AI 误删了情绪好但技术轻瑕疵的 keeper → AI 初筛后人工复核边界帧，别裸信。**CLI 自检**: 「AI 筛掉的里，有没有你其实想要的瞬间？复核过吗？」"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "pipeline-cull-raw-retouch-grade--walkthrough"
fi
